/// <reference types="astro/client" />

// Env, Cloudflare.Env, and process.env types are generated by `wrangler types`
// into worker-configuration.d.ts at the repo root (gitignored). Run:
//     npm run cf-typegen
// whenever wrangler.jsonc bindings change.

declare namespace App {
  interface Locals {
    db: import('./db').AppDb;
    auth: import('./lib/auth').AppAuth;
    user: {
      id: string;
      name: string;
      email: string;
      image: string | null | undefined;
      termsAcceptedAt: Date | null;
    } | null;
    session: {
      id: string;
      userId: string;
      token: string;
      expiresAt: Date;
    } | null;
    account: import('./lib/account').AccountContext | null;
  }
}

declare module 'cloudflare:workers' {
  interface ProvidedEnv extends Env {
    /**
     * URL of @baseout/server (the backup engine). Local dev: http://localhost:8787
     * (wrangler default port). Deployed: the deployed engine URL set via
     * `wrangler secret put BACKUP_ENGINE_URL --env <env>`.
     */
    BACKUP_ENGINE_URL: string;
    /** Shared secret with @baseout/server's INTERNAL_TOKEN. Sent as x-internal-token header on every call to the engine. */
    BACKUP_ENGINE_INTERNAL_TOKEN: string;
  }
}
